// Re-assert both forall|i| ensures with the same triggers so that
// z3 instantiates them on the same ground terms `post1_self_.page_array@[i]`
// and `post2_self_.page_array@[i]` (the original ensures use disjoint
// triggers per run, which left z3 unable to line them up).
assert(forall|i: int|
    #![trigger post1_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != index ==>
        post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
assert(forall|i: int|
    #![trigger post2_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != index ==>
        post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);

// Pointwise: for every valid index, the two runs produce equal Pages.
// - At i == index, every Page field is pinned by a direct ensures to
//   either pre_self_.page_array@[index].<field> or to `ref_count`, so
//   both Page values agree field-by-field.
// - At i != index, both equal pre_self_.page_array@[i] by the foralls
//   re-asserted just above.
assert forall|i: int| 0 <= i < NUM_PAGES implies
    post1_self_.page_array@[i] =~= post2_self_.page_array@[i]
by {
    if i == index as int {
    } else {
    }
}

// Sequence extensionality lifts the pointwise equality of Pages to a
// view-level equality of the two page_array sequences.
assert(post1_self_.page_array@ =~= post2_self_.page_array@);
